mapper.update:
update student s
set
    s.violation_count = s.violation_count + 1,
    s.violation_score = s.violation_score + #{score}
where id = #{id};

mapper.select:
select s.*,c.name clazzName from student s left join clazz c on s.clazz_id = c.id
and s.name like concat('%',#{name},'%')
and s.clazz_id = #{clazzId}
and s.degree <= #{degree}
